def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    positive_bins = bins[bins > 0]
    avg_capacity = np.mean(positive_bins) if positive_bins.size > 0 else 1
    variance = np.var(positive_bins) if positive_bins.size > 0 else 0.1
    skewness = np.sum(((positive_bins - avg_capacity) ** 3)) / (len(positive_bins) * (variance ** 1.5)) if variance > 0 else 0
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0 or capacity < item:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif ratio > 0.9:
            score = ((1 - ratio) ** 6) * 1.5 + 0.3
        elif 0.7 < ratio <= 0.9:
            score = np.exp(-ratio * 20) + 0.1
        elif 0.4 < ratio <= 0.7:
            temp = 0.0
            for k in range(1, 15):
                term = ((-1) ** (k+1)) * (ratio ** (k + 3)) / (k * 1.3)
                temp += term
            score = abs(temp) + 0.12
        else:
            temp = 0.0
            for p in range(1, 20):
                weight = 1 / (p ** 1.5)
                temp += ((-1) ** p) * (ratio ** (p + 2)) * weight
            score = abs(temp) + 0.15
        neighbors_influence = 0.0
        neighbors_weights_sum = 0.0
        neighbors_count = 0
        for offset in range(1, 10):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff = abs(capacity - neighbor_capacity)
                    norm_diff = diff / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 2.2)
                    influence = norm_diff * weight
                    if neighbor_capacity > avg_capacity + variance * 1.5:
                        influence *= 1.2
                    elif neighbor_capacity < avg_capacity - variance * 1.5:
                        influence *= 0.85
                    neighbors_influence += influence
                    neighbors_weights_sum += weight
                    neighbors_count += 1
        if neighbors_weights_sum > 0:
            neighbors_influence /= neighbors_weights_sum
        else:
            neighbors_influence = 0
        cap_factor = (capacity ** 0.65) + (avg_capacity ** 0.35) + (variance ** 0.1)
        if cap_factor == 0:
            cap_factor = 1
        penalty = 0
        if capacity < item:
            penalty = ((item - capacity) ** 3.5) * 0.5
        elif capacity > item * 2.5:
            penalty = 0.07
        if skewness > 1:
            penalty += 0.02
        if i % 5 == 0:
            score *= 0.75
            neighbors_influence *= 1.3
            penalty *= 1.2
        elif i % 3 == 0:
            score *= 1.15
            neighbors_influence *= 0.85
        elif i % 2 == 0:
            score *= 0.9
            neighbors_influence *= 1.1
        else:
            score *= 1.0
        if neighbors_count > 5 and neighbors_influence > 0.5:
            penalty += 0.03
        priority = score + neighbors_influence / cap_factor + penalty
        if priority < 0:
            priority = 0
        priorities[i] = priority
    finite = priorities[np.isfinite(priorities)]
    if finite.size == 0:
        return priorities
    max_finite = np.max(finite)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 5.5
    min_priority = np.min(priorities)
    max_priority = np.max(priorities)
    if max_priority - min_priority > 1e-6:
        for i in range(n):
            priorities[i] = (priorities[i] - min_priority) / (max_priority - min_priority)
    return priorities
